1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	type QuoteResult = { premium: number };
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  amulet: 60,
21	  sword: 100,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const PROCESSING_FEE = 5;
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	// Component-block pricing: 3 alike components of the same type (e.g. 3 runes
37	// or 3 moonstones) sold together are priced as a 60 G block instead of
38	// 3 × 25 = 75 G. Adjustment is applied to policy base for each component
39	// type with exactly 3 instances.
40	const COMPONENT_BLOCK_SIZE = 3;
41	const COMPONENT_BLOCK_PRICE = 60;
42	const COMPONENT_TYPES = ["rune", "moonstone"];
43	
44	function sumOver<T>(xs: T[], f: (x: T) => number): number {
45	  return xs.reduce((total, x) => total + f(x), 0);
46	}
47	
48	// MHPCO rounds quote premiums UP (in the office's favor).
49	function roundUpInFavorOfOffice(amount: number): number {
50	  return Math.ceil(amount);
51	}
52	
53	function basePremium(type: string): number {
54	  return BASE_PREMIUM[type] ?? 0;
55	}
56	
57	function itemBasePremium(item: QuoteItem): number {
58	  return basePremium(item.type);
59	}
60	
61	// Per-type adjustment when exactly COMPONENT_BLOCK_SIZE items of `type` are
62	// present in the step: replace raw N × base with the flat block price.
63	function componentBlockAdjustment(items: QuoteItem[]): number {
64	  return sumOver(COMPONENT_TYPES, (type) => {
65	    const count = items.filter((x) => x.type === type).length;
66	    return count === COMPONENT_BLOCK_SIZE
67	      ? COMPONENT_BLOCK_PRICE - COMPONENT_BLOCK_SIZE * basePremium(type)
68	      : 0;
69	  });
70	}
71	
72	function itemSurcharges(item: QuoteItem): number {
73	  const base = itemBasePremium(item);
74	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
75	  const highEnchantmentSurcharge =
76	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
77	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
78	      : 0;
79	  return curseSurcharge + highEnchantmentSurcharge;
80	}
81	
82	function priceQuoteStep(
83	  step: QuoteStep,
84	  yearsWithMHPCO: number,
85	  isFollowUp: boolean,
86	): QuoteResult {
87	  const policyBase =
88	    sumOver(step.items, itemBasePremium) + componentBlockAdjustment(step.items);
89	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
90	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
91	  const loyaltyDiscount =
92	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
93	      ? policyBase * LOYALTY_DISCOUNT_RATE
94	      : 0;
95	  const followUpDiscount = isFollowUp
96	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
97	    : 0;
98	  const premium = roundUpInFavorOfOffice(
99	    policyBase +
100	      itemSurchargeTotal +
101	      firstInsurance -
102	      loyaltyDiscount -
103	      followUpDiscount +
104	      PROCESSING_FEE,
105	  );
106	  return { premium };
107	}
108	
109	export function runScenario(scenario: Scenario): {
110	  results: QuoteResult[];
111	} {
112	  const results = scenario.steps.map((step, index) =>
113	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
114	  );
115	  return { results };
116	}
