interface QuoteStep {
  op: "quote";
  items: QuoteItem[];
}

interface DamageEntry {
  itemType: string;
  amount: number;
}

interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: DamageEntry[];
  };
}

type Step = QuoteStep | ClaimStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

type QuoteResult = { premium: number };
type ClaimResult = { payout: number };
type StepResult = QuoteResult | ClaimResult;

