function processClaimStep(_step: ClaimStep): ClaimResult {
  return { payout: 0 };
}

export function runScenario(scenario: Scenario): {
  results: StepResult[];
} {
  const results = scenario.steps.map((step, index) =>
    step.op === "quote"
      ? priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0)
      : processClaimStep(step),
  );
  return { results };
}
